from collections import deque
import math

def solve(nums: list[int]) -> int:
    n = len(nums)
    visited = [False] * n
    queue = deque([[0, 0]])  # [index, steps]
    visited[0] = True

    while queue:
        i, steps = queue.popleft()
        if i == n - 1:
            return steps

        # Move to adjacent cells
        for next_i in [i - 1, i + 1]:
            if 0 <= next_i < n and not visited[next_i]:
                visited[next_i] = True
                queue.append([next_i, steps + 1])

        # Prime teleport
        num = nums[i]
        if is_prime(num):
            for j in range(n):
                if nums[j] % num == 0 and j != i and not visited[j]:
                    visited[j] = True
                    queue.append([j, steps + 1])

    return -1  # If no path found (should not happen as per problem constraints)

def is_prime(num: int) -> bool:
    if num <= 1:
        return False
    if num == 2:
        return True
    if num % 2 == 0:
        return False
    for i in range(3, int(math.sqrt(num)) + 1, 2):
        if num % i == 0:
            return False
    return True
